<script setup lang="ts">
import { computed,onMounted,ref,watch } from 'vue'
import { useRoute } from 'vue-router'
import MesLayout from '@/layouts/MesLayout.vue'
import SopModelViewer from '@/components/SopModelViewer.vue'
import { del,get,getBlob,post,put,upload } from '@/api/client'
type Step={id:number;stepNo:number;stepName:string;instruction?:string;contentType?:string;minStaySeconds?:number;confirmRequired?:boolean;parameterRequired?:boolean;photoRequired?:boolean;enabled?:boolean}
type Attachment={id:number;stepId?:number;attachmentType?:string;fileName:string;fileSize?:number;fileUrl?:string};type Model={id:number;fileName:string;fileUrl:string};type SopVersion={id:number;modelVersionId?:number}
const route=useRoute(),versionId=computed(()=>Number(route.query.versionId||0)),title=computed(()=>String(route.query.name||'SOP 步骤编排'));const rows=ref<Step[]>([]),attachments=ref<Attachment[]>([]),model=ref<Model|null>(null),error=ref(''),loading=ref(false),editing=ref(false),current=ref<Partial<Step>>({}),uploading=ref(false),renumbering=ref(false)
async function load(){if(!versionId.value){error.value='请先选择 SOP 版本';rows.value=[];attachments.value=[];model.value=null;return};loading.value=true;error.value='';try{const [steps, files, version]=await Promise.all([get<Step[]>(`/production/sop/versions/${versionId.value}/steps`),get<Attachment[]>(`/production/sop/versions/${versionId.value}/attachments`),get<SopVersion>(`/production/sop/versions/${versionId.value}`)]);rows.value=steps;attachments.value=files;model.value=version.modelVersionId?{id:version.modelVersionId,fileName:'当前版本模型',fileUrl:''}:null}catch(e){error.value=e instanceof Error?e.message:'步骤加载失败'}finally{loading.value=false}}
function edit(row?:Step){current.value=row?{...row}:{stepNo:rows.value.length+1,stepName:'',instruction:'',contentType:'TEXT',minStaySeconds:0,confirmRequired:true,enabled:true};editing.value=true}
function requirements(row: Step) { return [row.parameterRequired ? '参数' : '', row.photoRequired ? '拍照' : ''].filter(Boolean).join(' ') || '-' }
async function save(){try{const payload={...current.value,stepNo:Number(current.value.stepNo),minStaySeconds:Number(current.value.minStaySeconds||0)};if(current.value.id)await put(`/production/sop/steps/${current.value.id}`,payload);else await post(`/production/sop/versions/${versionId.value}/steps`,payload);editing.value=false;await load()}catch(e){error.value=e instanceof Error?e.message:'保存步骤失败'}}
async function remove(row:Step){if(!confirm(`确定删除步骤「${row.stepName}」吗？`))return;try{await del(`/production/sop/steps/${row.id}`);await load()}catch(e){error.value=e instanceof Error?e.message:'删除失败'}}
async function uploadAttachment(event: Event, stepId?: number) { const file=(event.target as HTMLInputElement).files?.[0]; if(!file)return; uploading.value=true; try { const data=new FormData();data.append('file',file);if(stepId)data.append('stepId',String(stepId));await upload(`/production/sop/versions/${versionId.value}/attachments`,data);await load() } catch(e){error.value=e instanceof Error?e.message:'附件上传失败'}finally{uploading.value=false;(event.target as HTMLInputElement).value=''} }
async function uploadModel(event: Event) { const file=(event.target as HTMLInputElement).files?.[0];if(!file)return;uploading.value=true;try{const data=new FormData();data.append('file',file);model.value=await upload<Model>(`/production/sop/versions/${versionId.value}/models`,data)}catch(e){error.value=e instanceof Error?e.message:'GLB 模型上传失败'}finally{uploading.value=false;(event.target as HTMLInputElement).value=''} }
async function deleteAttachment(file:Attachment){if(!confirm(`确定删除附件「${file.fileName}」吗？`))return;try{await del(`/production/sop/attachments/${file.id}`);await load()}catch(e){error.value=e instanceof Error?e.message:'附件删除失败'}}
async function openAttachment(file: Attachment) {
  const tab = window.open('', '_blank')
  try {
    const blob = await getBlob(`/production/sop/files/${file.id}`)
    const url = URL.createObjectURL(blob)
    if (tab) tab.location.href = url
    else window.location.assign(url)
    window.setTimeout(() => URL.revokeObjectURL(url), 60_000)
  } catch (e) {
    tab?.close()
    error.value = e instanceof Error ? e.message : '附件打开失败'
  }
}
async function renumber(){if(!rows.value.length)return;if(!confirm(`确定将当前 ${rows.value.length} 个步骤重新编号为 1~${rows.value.length} 吗？`))return;renumbering.value=true;error.value='';try{const sorted=[...rows.value].sort((a,b)=>a.stepNo-b.stepNo);for(let i=0;i<sorted.length;i++){await put(`/production/sop/steps/${sorted[i].id}`,{...sorted[i],stepNo:i+1,minStaySeconds:Number(sorted[i].minStaySeconds||0)})};await load()}catch(e){error.value=e instanceof Error?e.message:'重新编号失败'}finally{renumbering.value=false}}
onMounted(load);watch(versionId,load)
</script>
<template><MesLayout active="sop-steps"><header class="app-header"><div class="header-breadcrumb"><span>电子 SOP</span><span class="bc-sep">/</span><span class="bc-current">步骤编排</span></div><div class="header-actions"><label class="btn btn-secondary btn-sm">{{uploading?'上传中...':'上传附件'}}<input type="file" hidden :disabled="uploading" @change="uploadAttachment"></label><label class="btn btn-secondary btn-sm">上传 GLB<input type="file" hidden accept=".glb" :disabled="uploading" @change="uploadModel"></label><button class="btn btn-primary btn-sm" :disabled="!versionId" @click="edit()">+ 添加步骤</button><button class="btn btn-secondary btn-sm" :disabled="!versionId||!rows.length||renumbering" @click="renumber">{{renumbering?'编号中...':'重新编号'}}</button><span class="user-avatar">张</span></div></header><main class="app-main"><h1 class="page-title">{{title}}</h1><div v-if="error" class="alert alert-error mb-5"><span class="alert-icon">!</span>{{error}}</div><div class="data-table-wrap"><table class="data-table"><thead><tr><th>步骤号</th><th>步骤标题</th><th>操作说明</th><th>最短停留</th><th>确认</th><th>参数/拍照</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-if="loading"><td colspan="8">正在加载...</td></tr><tr v-else-if="!rows.length"><td colspan="8">暂无步骤</td></tr><tr v-for="row in rows" :key="row.id"><td class="cell-mono">{{row.stepNo}}</td><td>{{row.stepName}}</td><td>{{row.instruction||'-'}}</td><td>{{row.minStaySeconds||0}} 秒</td><td>{{row.confirmRequired?'需要':'无需'}}</td><td>{{requirements(row)}}</td><td><span class="badge badge-status-ok"><span class="badge-dot"></span>{{row.enabled?'启用':'停用'}}</span></td><td class="cell-actions"><label class="btn btn-ghost btn-sm">附件<input type="file" hidden @change="uploadAttachment($event,row.id)"></label><button class="btn btn-ghost btn-sm" @click="edit(row)">编辑</button><button class="btn btn-ghost btn-sm" @click="remove(row)">删除</button></td></tr></tbody></table><div class="pagination">共 {{rows.length}} 个步骤</div></div><section class="asset-grid"><div class="card"><div class="card-header"><h2 class="card-title">版本附件</h2><span class="text-muted">{{attachments.length}} 个文件</span></div><div v-if="!attachments.length" class="text-muted">暂无附件</div><div v-for="file in attachments" :key="file.id" class="asset-row"><button class="asset-link" @click="openAttachment(file)">{{file.fileName}}</button><span class="text-muted">{{file.attachmentType||'FILE'}}{{file.stepId?` · 步骤 ${file.stepId}`:''}}</span><button class="btn btn-ghost btn-sm" @click="deleteAttachment(file)">删除</button></div></div><div class="card"><div class="card-header"><h2 class="card-title">3D 模型预览</h2><span v-if="model" class="text-muted">{{model.fileName}}</span></div><SopModelViewer :model-version-id="model?.id" /></div></section><div v-if="editing" class="sop-mask" @click.self="editing=false"><form class="sop-dialog" @submit.prevent="save"><div class="card-header"><h2 class="card-title">{{current.id?'编辑':'添加'}}步骤</h2></div><div class="sop-form"><label>步骤号<input v-model.number="current.stepNo" class="form-input" type="number" min="1" required></label><label>步骤标题<input v-model="current.stepName" class="form-input" required></label><label class="wide">操作说明<textarea v-model="current.instruction" class="form-input" rows="3"></textarea></label><label>最短查看秒数<input v-model.number="current.minStaySeconds" class="form-input" type="number" min="0"></label><label>内容类型<select v-model="current.contentType" class="form-select"><option value="TEXT">文本</option><option value="IMAGE">图片</option><option value="VIDEO">视频</option></select></label></div><div class="check-row"><label><input v-model="current.confirmRequired" type="checkbox"> 需要确认</label><label><input v-model="current.parameterRequired" type="checkbox"> 必填参数</label><label><input v-model="current.photoRequired" type="checkbox"> 必传照片</label><label><input v-model="current.enabled" type="checkbox"> 启用</label></div><div class="dialog-actions"><button type="button" class="btn btn-secondary" @click="editing=false">取消</button><button class="btn btn-primary">保存</button></div></form></div></main><footer class="app-statusbar"><span class="statusbar-item"><span class="dot ok"></span>步骤编排</span><span class="statusbar-sep">|</span><span class="statusbar-item">{{rows.length}} 个步骤</span></footer></MesLayout></template>
<style scoped>.sop-mask{position:fixed;inset:0;z-index:20;background:rgba(15,23,42,.38);display:grid;place-items:center}.sop-dialog{width:min(640px,calc(100vw - 32px));background:#fff;border-radius:8px;padding:20px;box-shadow:0 18px 50px rgba(15,23,42,.28)}.sop-form{display:grid;grid-template-columns:1fr 1fr;gap:14px}.sop-form label{display:grid;gap:7px;font-size:13px}.wide{grid-column:1/-1}.check-row{display:flex;flex-wrap:wrap;gap:16px;margin-top:16px;font-size:13px}.dialog-actions{display:flex;justify-content:flex-end;gap:10px;margin-top:22px}.asset-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:18px}.asset-row{display:flex;gap:8px;align-items:center;padding:10px 0;border-top:1px solid var(--color-border,#e5e7eb)}.asset-link{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;text-align:left;border:0;background:none;color:var(--color-primary,#2563eb);cursor:pointer;padding:0;font:inherit}@media(max-width:900px){.asset-grid{grid-template-columns:1fr}}</style>
